package kr.gampa.battlegrounds.combat; public record BallisticVector(double x,double y,double z){public BallisticVector add(BallisticVector o){return new BallisticVector(x+o.x,y+o.y,z+o.z);}public BallisticVector multiply(double s){return new BallisticVector(x*s,y*s,z*s);}public double distance(BallisticVector o){double dx=x-o.x,dy=y-o.y,dz=z-o.z;return Math.sqrt(dx*dx+dy*dy+dz*dz);}public BallisticVector lerp(BallisticVector o,double t){return new BallisticVector(x+(o.x-x)*t,y+(o.y-y)*t,z+(o.z-z)*t);}}